mapper.insert:
insert into `quote` (
    quote_no, demand_id, developer_id, price_total, estimated_days,
    tech_solution, delivery_desc, attach_json, valid_until, status,
    selected_at, version, created_at, updated_at
) values (
    #{quoteNo}, #{demandId}, #{developerId}, #{priceTotal}, #{estimatedDays},
    #{techSolution}, #{deliveryDesc}, #{attachJson}, #{validUntil}, #{status},
    #{selectedAt}, #{version}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from `quote`
where demand_id = #{demandId}
  and developer_id = #{developerId}
limit 1

mapper.update:
update `quote`
set status = 2,
    updated_at = now()
where demand_id = #{demandId}
  and id != #{selectedQuoteId}
  and status = 0
